  ('disabled-6f0ba476-moex-00032', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'essay', '下列為乙公司的比較資產負債表
