  ('disabled-6f0ba476-moex-00033', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司倉庫於 X5 年 5 月 1 日發生火災，倉庫內剩餘存貨的估計殘值為 $34,500，該存貨原成本為$28,500，原本售價為$38,000。若X5年1月1日 存貨$187,500，X5年1月1日至5月1日間的進貨$1,218,000（含起運點 交貨之在途進貨成本$178,500），進貨退回及折讓$18,000，銷貨總額 $1,410,000，銷貨退回$36,000，銷貨運費$13,500。若甲公司毛利率為銷貨 淨額之25%，則以毛利法計算應認列之火災損失金額為何？', '["$138,000", "$144,000", "$150,000", "$174,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00034', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司過去三年的平均毛利率為38%，年中發生火災導致存貨毀損，僅剩 $6,500 存貨完好。公司帳冊內有關資料如下：期初存貨$136,600、進貨 $397,500、進貨運費$3,680、進貨折扣$4,000、銷貨收入$645,600、銷貨退 回$4,600、銷貨運費$10,000，試問甲公司存貨損失為何？', '["$129,860", "$136,250", "$136,360", "$142,560"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00035', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙公司 X4 年的期初存貨成本$27,000（3,000 件），該年度共採購三次，第 一次進貨3,000件，成本共計$36,000，第二次進貨2,000件，成本共計$30,000 ，第三次進貨3,000件，成本共計$53,960，X4年度共出售8,000件。若該公 司按定期盤存制之加權平均法計算存貨成本，則期末存貨成本為何？', '["$24,000", "$33,600", "$37,500", "$40,080"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00036', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X1 年初購入股票投資$700,000 並分類為透過其他綜合損益按公 允價值衡量之金融資產，此股票投資 X1 年底之公允價值為$707,000，該 公司於 X2 年中按當時公允價值$696,500 全數處分該項投資。若不考慮所 得稅與交易成本之影響，則該項投資對甲公司 X2 年其他綜合損益之影響 數為何？', '["增加$7,000", "減少$3,500", "減少$7,000", "減少$10,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00037', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '丙公司於 X4 年 1 月 1 日以$1,500,000 買入丁公司普通股股份 40%。若丁 公司在X4年度內宣告並發放現金股利$1,200,000及盈餘轉增資$1,800,000 ，並報導當年度之稅後淨利為$3,000,000。試問丙公司於X4年12月31日 資產負債表上應報導對丁公司股權投資之帳面金額為多少？', '["$1,200,000", "$1,500,000", "$2,220,000", "$2,700,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00038', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X4年7月1日以$262,500購入乙公司發行面額$300,000，票面利率 8%之公司債，每年6月30日及12月31日付息。假設此債券投資之有效利 率為10%，甲公司擬將債券持有至到期日，X4年底此債券之市價為$285,000 ，則甲公司X4年底資產負債表上應報導該債券投資之金額為多少？', '["$262,500", "$263,625", "$273,000", "$285,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00039', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙公司於X3年1月1日以$320,000購入機器設備，估計耐用年限為5年 ，估計殘值為$20,000，採用年數合計法提列折舊。X5 年1月1 日，公司 決定改採直線法提列折舊，而且發現該機器設備還可再用5年，新的殘值 為$10,000。則該機器設備X5年之折舊金額為多少？', '["$26,000", "$28,000", "$30,000", "$32,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00040', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司在 X1 年初為讓印刷作業更有效率，欲重置一台印刷機，下列資料 為當日的相關資訊： 新印刷機的購買價格 $1,500,000 舊印刷機的原始成本 980,000 舊印刷機的帳面價值 100,000 舊印刷機的公允價值 40,000 新印刷機的安裝成本 200,000 若甲公司是以舊印刷機直接交換新印刷機，並支付對方現金$1,460,000，此 一交換交易具商業實質，則該公司應記錄新印刷機的成本為多少金額？', '["$1,500,000", "$1,600,000", "$1,660,000", "$1,700,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
